/**
 * @munesoft/envx
 * One-line .env loader, validator, and type-safe config for Node.js.
 *
 * Usage:
 *   import envx from "@munesoft/envx";
 *   await envx();
 *
 *   // Or with inline schema:
 *   await envx({
 *     schema: {
 *       PORT: { type: "number", default: 3000 },
 *       API_KEY: { type: "string", required: true }
 *     }
 *   });
 */

import { load } from "./loader.js";
import { parse } from "./parser.js";
import { validate } from "./validator.js";
import { coerce } from "./coerce.js";
import { loadConfig } from "./configLoader.js";

/**
 * Load, validate, and apply environment variables.
 *
 * @param {import('../types/index').LoadOptions} [options]
 * @returns {Promise<Record<string, any>>}
 */
export default async function envx(options = {}) {
  return load(options);
}

// Named exports for advanced usage
export { load, parse, validate, coerce, loadConfig };
